const raw = $input.first().json;
const body = raw.body || raw;
const query = raw.query || {};
return [{ json: { ...query, ...body, action: body.action || query.action || 'ping' } }];

const request = $('Normalize API Request').item.json;
const action = request.action || 'ping';
const norm = v => String(v || '').trim().toLowerCase();
const get = (row, keys, fallback='') => { for (const k of keys) { if (row[k] !== undefined && row[k] !== null && String(row[k]).trim() !== '') return row[k]; } return fallback; };
function monthKey(value) {
  if (!value) return '';
  const raw = String(value).trim();
  const d = new Date(raw);
  if (!Number.isNaN(d.getTime())) return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-01`;
  const m = raw.match(/^(\d{4})-(\d{2})/);
  if (m) return `${m[1]}-${m[2]}-01`;
  return raw;
}
function monthLabel(value) {
  const key = monthKey(value);
  const d = new Date(key);
  if (!Number.isNaN(d.getTime())) return d.toLocaleString('en-IN',{month:'short',year:'numeric'});
  return String(value || '');
}
function rows(nodeName) {
  try { return $items(nodeName).map(i => i.json).filter(r => !r.error && Object.keys(r).length); } catch(e) { return []; }
}
const sessions = rows('Read OTP Store');
const tasksRaw = rows('Read Portal Tasks');
const submissionsRaw = rows('Read Portal Submissions');
const legacyRaw = rows('Read Legacy Feedback');
function validSession() {
  if (action === 'ping' || action === 'available_months') return { email: '', role: 'public' };
  const token = String(request.sessionToken || '').trim();
  if (!token) throw new Error('Missing session token. Please login again.');
  const match = sessions.filter(r => String(r.SessionToken || '').trim() === token && norm(r.Used) === 'true')
    .sort((a,b) => new Date(b.UsedAt || b.CreatedAt || 0).getTime() - new Date(a.UsedAt || a.CreatedAt || 0).getTime())[0];
  if (!match) throw new Error('Invalid or expired session. Please login again.');
  const usedAt = new Date(match.UsedAt || match.CreatedAt || '').getTime();
  if (!usedAt || Number.isNaN(usedAt) || Date.now() > usedAt + 12*60*60*1000) throw new Error('Session expired. Please login again.');
  return { email: norm(match.Email), role: norm(match.Role), sessionToken: token };
}
const session = validSession();
function mapTask(row) {
  const id = String(get(row,['Task_ID','TaskId','taskId'])).trim();
  return {
    taskId: id,
    month: get(row,['Month','month']),
    coachId: get(row,['Coach_ID','coachId']),
    coachName: get(row,['Coach_Name','coachName']),
    coachEmail: norm(get(row,['Coach_Email','coachEmail'])),
    studentId: get(row,['Student_ID','studentId']),
    studentName: get(row,['Student_Name','studentName']),
    studentEmail: get(row,['Student_Email','studentEmail']),
    lichessId: get(row,['Lichess_ID','lichessId']),
    batchCode: get(row,['Batch_Code','batchCode']),
    studentRating: get(row,['Student_Rating','studentRating']),
    taskStatus: get(row,['Task_Status','taskStatus'],'Pending'),
    submissionStatus: get(row,['Submission_Status','submissionStatus'],'Pending'),
    mentorStatus: get(row,['Mentor_Status','mentorStatus'],'Pending'),
    assignedOn: get(row,['Assigned_On','assignedOn']),
    submittedOn: get(row,['Submitted_On','submittedOn']),
    reviewedOn: get(row,['Reviewed_On','reviewedOn']),
    returnedOn: get(row,['Returned_On','returnedOn']),
    lastUpdated: get(row,['Last_Updated','lastUpdated'])
  };
}
function mapFeedback(row) {
  return {
    studentRating: get(row,['Student_Rating','studentRating']),
    gamesPlayed: get(row,['Games_Played','GamesPlayed','gamesPlayed']),
    wins: get(row,['Wins','wins']),
    draws: get(row,['Draws','draws']),
    losses: get(row,['Losses','losses']),
    ratingChange: get(row,['Rating_Change','ratingChange']),
    puzzleActivity: get(row,['Puzzle_Activity','Puzzle_Activities','puzzleActivity']),
    bestResult: get(row,['Best_Result','bestResult']),
    puzzleConsistency: get(row,['Puzzle_Consistency','puzzleConsistency']),
    skillLevel: get(row,['Skill_Level','skillLevel']),
    classPerformance: get(row,['Class_Performance','classPerformance']),
    strengths: get(row,['Strengths','strengths']),
    improvementAreas: get(row,['Improvement_Areas','Improvement_Area','improvementAreas']),
    focusNextMonth: get(row,['Focus_Next_Month','focusNextMonth']),
    overallComment: get(row,['Overall_Comment','overallComment']),
    mentorRemark: get(row,['Mentor_Remark','mentorRemark']),
    mentorNotes: get(row,['Mentor_Notes','mentorNotes'])
  };
}
function mapSubmission(row) {
  return {
    submissionId: get(row,['Submission_ID','submissionId']), taskId: get(row,['Task_ID','taskId']), month: get(row,['Month','month']),
    coachId: get(row,['Coach_ID','coachId']), coachName: get(row,['Coach_Name','coachName']), coachEmail: norm(get(row,['Coach_Email','coachEmail'])),
    studentId: get(row,['Student_ID','studentId']), studentName: get(row,['Student_Name','studentName']), studentEmail: get(row,['Student_Email','studentEmail']),
    lichessId: get(row,['Lichess_ID','lichessId']), batchCode: get(row,['Batch_Code','batchCode']),
    submissionStatus: get(row,['Submission_Status','submissionStatus'],'Submitted'), mentorStatus: get(row,['Mentor_Status','mentorStatus'],'Pending'),
    submittedOn: get(row,['Submitted_On','Timestamp','submittedOn']), reviewedOn: get(row,['Reviewed_On','reviewedOn']), returnedOn: get(row,['Returned_On','returnedOn']), lastUpdated: get(row,['Last_Updated','lastUpdated']),
    feedback: mapFeedback(row), raw: row
  };
}
let tasks = tasksRaw.map(mapTask).filter(t => t.taskId);
let submissions = submissionsRaw.map(mapSubmission).filter(s => s.taskId);
const latestSub = {};
submissions.sort((a,b)=>new Date(a.lastUpdated||a.reviewedOn||a.submittedOn||0)-new Date(b.lastUpdated||b.reviewedOn||b.submittedOn||0)).forEach(s=>{ latestSub[s.taskId]=s; });
function mergedTask(t) {
  const s = latestSub[t.taskId];
  if (!s) return { ...t, feedback: {} };
  return { ...t, submissionStatus: s.submissionStatus || t.submissionStatus, mentorStatus: s.mentorStatus || t.mentorStatus, taskStatus: s.mentorStatus === 'Approved' ? 'Approved' : (s.mentorStatus === 'Returned' ? 'Returned' : (s.submissionStatus || 'Submitted')), submittedOn: s.submittedOn || t.submittedOn, reviewedOn: s.reviewedOn || t.reviewedOn, returnedOn: s.returnedOn || t.returnedOn, lastUpdated: s.lastUpdated || t.lastUpdated, feedback: s.feedback };
}
tasks = tasks.map(mergedTask);
const requestedMonth = monthKey(request.month || '');
const requestedEmail = norm(request.email || session.email || '');
function byMonth(t){ return !requestedMonth || monthKey(t.month) === requestedMonth; }
function summary(list){ return { active:list.length, submitted:list.filter(t=>norm(t.submissionStatus)==='submitted'||norm(t.taskStatus)==='submitted').length, pending:list.filter(t=>norm(t.taskStatus).includes('pending')||norm(t.submissionStatus).includes('pending')).length, returned:list.filter(t=>norm(t.mentorStatus)==='returned'||norm(t.taskStatus)==='returned').length, approved:list.filter(t=>norm(t.mentorStatus)==='approved'||norm(t.taskStatus)==='approved').length, overdue:0 }; }
if (action === 'ping') return [{json:{ok:true,data:{message:'n8n-only backend connected'}}}];
if (action === 'available_months') {
  const all = [...tasksRaw.map(r=>get(r,['Month'])), ...submissionsRaw.map(r=>get(r,['Month'])), ...legacyRaw.map(r=>get(r,['Month']))].filter(Boolean);
  const seen = [...new Set(all.map(monthKey))].filter(Boolean).sort();
  const labels = seen.length ? seen.map(monthLabel) : [monthLabel(new Date())];
  return [{json:{ok:true,data:{months:labels, defaultMonth: labels[labels.length-1]}}}];
}
if (action === 'coach_dashboard') {
  if (session.role !== 'coach' && session.role !== 'mentor') throw new Error('Coach access required.');
  const list = tasks.filter(t=>byMonth(t)).filter(t=> session.role==='mentor' ? (!requestedEmail || t.coachEmail===requestedEmail) : t.coachEmail===session.email);
  return [{json:{ok:true,data:{coachEmail: requestedEmail || session.email, month: request.month, summary: summary(list), tasks:list}}}];
}
if (action === 'mentor_dashboard') {
  if (session.role !== 'mentor') throw new Error('Mentor access required.');
  const list = tasks.filter(t=>byMonth(t)).filter(t=>['submitted','returned','pending'].includes(norm(t.mentorStatus)) || norm(t.submissionStatus)==='submitted');
  return [{json:{ok:true,data:{month:request.month, summary:summary(list), tasks:list}}}];
}
if (action === 'approved_dashboard') {
  if (session.role !== 'mentor') throw new Error('Mentor access required.');
  const list = tasks.filter(t=>byMonth(t)).filter(t=>norm(t.mentorStatus)==='approved'||norm(t.taskStatus)==='approved');
  return [{json:{ok:true,data:{month:request.month, tasks:list, summary:summary(list)}}}];
}
if (action === 'task') {
  const t = tasks.find(x=>String(x.taskId)===String(request.taskId));
  if (!t) throw new Error('Task not found.');
  if (session.role==='coach' && t.coachEmail !== session.email) throw new Error('This task is not assigned to this coach.');
  return [{json:{ok:true,data:t}}];
}
if (action === 'history') {
  const t = tasks.find(x=>String(x.taskId)===String(request.taskId));
  if (!t) throw new Error('Task not found.');
  const sid = String(t.studentId||'').trim();
  const lich = norm(t.lichessId||'');
  const old = legacyRaw.filter(r=>String(get(r,['Student_ID','Student Id','studentId'])).trim()===sid || (lich && norm(get(r,['Lichess_ID','Lichess Id','lichessId']))===lich));
  const newer = submissions.filter(s=>String(s.studentId||'').trim()===sid || (lich && norm(s.lichessId)===lich));
  return [{json:{ok:true,data:{old,newer}}}];
}
if (action === 'fetch_lichess') {
  return [{json:{ok:true,data:{message:'Lichess fetch disabled in n8n-only build. Paste/update stats manually.'}}}];
}
if (['initialize','sync_legacy','launch_tasks','send_reminders'].includes(action)) {
  if (session.role !== 'mentor') throw new Error('Mentor access required.');
  return [{json:{ok:true,data:{message:`${action} handled by n8n-only mode. Use Google Sheets tabs directly or add the optional admin workflow.`, tasks: tasks.length, legacyRows: legacyRaw.length}}}];
}
throw new Error('Unsupported action: ' + action);
